mapper.update:
UPDATE review
SET REVIEW_CONTENT = #{reviewContent},
    THUMBS_UP = #{thumbsUp}
WHERE REVIEW_ID = #{reviewId}

mapper.delete:
DELETE FROM review
WHERE REVIEW_ID = #{reviewId}
  AND (ID = #{requesterId} OR #{requesterId} = 'Admin' OR #{requesterId} = 'admin')

mapper.select:
SELECT WRITER_ID
FROM recipe
WHERE RECIPE_ID = #{recipeCode}
